#include<bits/stdc++.h>
using namespace std;

char a[505],b[505];

int main()
{
	int lena,lenb;
	scanf("%s",a);
	lena=strlen(a);
	if(a[lena-1]=='.')
	{
		a[lena-1]='\0';
		lena--;
	}
	strcpy(b,a);
	while(~scanf("%s",a))
	{
		lenb=strlen(a);
		if(a[lenb-1]=='.')
		{
			a[lenb-1]='\0';
			lenb--;
		}
		if(lenb>lena)
		{
			lena=lenb;
			strcpy(b,a);
		}
	}
	printf("%s",b);
	return 0;
}
